class Solution {
public:
    int maximumLengthSubstring(string s) {
        int maxLen = 0;
        int left = 0;
        unordered_map<char, int> charCount;

        for (int right = 0; right < s.size(); ++right) {
            charCount[s[right]]++;

            while (charCount[s[right]] > 2) {
                charCount[s[left]]--;
                if (charCount[s[left]] == 0) {
                    charCount.erase(s[left]);
                }
                left++;
            }

            maxLen = max(maxLen, right - left + 1);
        }

        return maxLen;
    }
};
